import{_ as a,o as s,c as t,ae as i}from"./chunks/framework.CbfcRfVi.js";const p=JSON.parse('{"title":"Baikal issues and fixes","description":"","frontmatter":{},"headers":[],"relativePath":"ps4/baikal-issues.md","filePath":"ps4/baikal-issues.md","lastUpdated":1777892371000}'),o={name:"ps4/baikal-issues.md"};function l(r,e,n,h,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="baikal-issues-and-fixes" tabindex="-1">Baikal issues and fixes <a class="header-anchor" href="#baikal-issues-and-fixes" aria-label="Permalink to &quot;Baikal issues and fixes&quot;">​</a></h1><p>If you landed here, it means you have the shittiest southbridge of them all: the ass Baikal chip. Unfortunately there aren&#39;t many fixes for this chip, but you may be able to get a working installation.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The community has been working hard to update Baikal systems to a stable 6.18 kernel. It may be released soon.</p></div><h2 id="arch-linux-mesa-packages-for-baikal" tabindex="-1">Arch Linux Mesa packages for Baikal <a class="header-anchor" href="#arch-linux-mesa-packages-for-baikal" aria-label="Permalink to &quot;Arch Linux Mesa packages for Baikal&quot;">​</a></h2><p>Thanks to deeWaardt, we now have packages specifically built for Baikal consoles, which means that this repo contains Mesa 25.1 and old libdrm that works on kernel 5.4. GitHub download <a href="https://github.com/deWaardt/ps4-baikal-graphics/tree/main" target="_blank" rel="noreferrer">here</a>.</p><h2 id="things-that-don-t-work-on-baikal-consoles" tabindex="-1">Things that don&#39;t work on Baikal consoles <a class="header-anchor" href="#things-that-don-t-work-on-baikal-consoles" aria-label="Permalink to &quot;Things that don&#39;t work on Baikal consoles&quot;">​</a></h2><ul><li>Stable kernels are on version 5.4 (newer are in development)</li><li>Higher Mesa than 25.1 will not work due to upgraded <code>libdrm</code> that requires newer kernel</li><li>Wayland as default graphics platform won&#39;t work, only X11 does, you can however launch a Wayland session after first executing X11</li><li>Ethernet (LAN) doesn&#39;t work</li><li>Internal HDD writing speeds are slow due to UFS encryption, you can however install internally (theoretically? you need a different initramfs).</li></ul><blockquote><p>List by uar</p><p>Check out their website&#39;s baikal section <a href="https://uar.no/ps4/baikal/" target="_blank" rel="noreferrer">here</a></p></blockquote><h2 id="why-is-baikal-still-unsupported" tabindex="-1">Why is Baikal still unsupported? <a class="header-anchor" href="#why-is-baikal-still-unsupported" aria-label="Permalink to &quot;Why is Baikal still unsupported?&quot;">​</a></h2><p>Because there are almost no developers willing to put so much effort into the chip.</p><p>Aeolia and Belize work almost flawlessly between each others because they are very similar, but Baikal is completely different and adds a lot of work to the entire scene. This means that you are still stuck with older kernels which don&#39;t support newer <code>libdrm</code> versions which in turn don&#39;t support newer <code>mesa-git</code> versions and so on. It&#39;s an endless cycle.</p><p>In reality there&#39;s not much to say, so if you have any issues, send a message on the Discords.</p>',12)])])}const k=a(o,[["render",l]]);export{p as __pageData,k as default};
